import React from 'react';
import { Card, CardContent, Typography, Stack, Box, Divider } from '@mui/material';
import response from './response.json';

interface TipCalculatorData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    billTotal: number;
    tipPercentage: number;
    tipAmount: number;
    totalWithTip: number;
    people: number;
    perPersonAmount: number;
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const tipCalculatorData = response.data as TipCalculatorData;
  const { billTotal, tipPercentage, tipAmount, totalWithTip, people, perPersonAmount } = tipCalculatorData.data;
  const { primaryColor, accentColor } = tipCalculatorData.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 360, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Typography variant="h6" sx={{ color: primaryColor, mb: 2 }}>
          Easy Tip Calculator
        </Typography>
        <Stack spacing={1}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Bill Total
            </Typography>
            <Typography variant="h5" fontWeight={500}>
              ${billTotal.toFixed(2)}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Tip ({tipPercentage}%)
            </Typography>
            <Typography variant="h5" fontWeight={500} sx={{ color: accentColor }}>
              ${tipAmount.toFixed(2)}
            </Typography>
          </Box>

          <Divider sx={{ my: 1 }} />

          <Box>
            <Typography variant="body2" color="text.secondary">
              Total with Tip
            </Typography>
            <Typography variant="h5" fontWeight={500}>
              ${totalWithTip.toFixed(2)}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              People
            </Typography>
            <Typography variant="h5" fontWeight={500}>
              {people}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Per Person
            </Typography>
            <Typography variant="h5" fontWeight={500} sx={{ color: primaryColor }}>
              ${perPersonAmount.toFixed(2)}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
